    logger.debug("broadcast %s session=%s event=%s", ws_type, session_id, event_name)

    await manager.broadcast(
        {
            "type": ws_type,
            "platform": "claude",
            "session_id": session_id,
            "event_name": event_name,
            "tool_name": tool_name,
            "agent_id": agent_id,
            "cwd": cwd,
            "timestamp": timestamp,
        }
    )


